import{_ as a,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Modo Ultrawork: Activa Todas las Funciones | oh-my-opencode","description":"Aprende el modo Ultrawork de oh-my-opencode y sus características principales, incluyendo el uso de la palabra clave ultrawork, cambios de comportamiento al activar, mecanismo de exploración paralela, verificación de finalización forzada y colaboración de agentes, para activar rápidamente todas las funciones avanzadas.","frontmatter":{"title":"Modo Ultrawork: Activa Todas las Funciones | oh-my-opencode","sidebarTitle":"Activa Todas las Funciones","subtitle":"Modo Ultrawork: Activa Todas las Funciones","description":"Aprende el modo Ultrawork de oh-my-opencode y sus características principales, incluyendo el uso de la palabra clave ultrawork, cambios de comportamiento al activar, mecanismo de exploración paralela, verificación de finalización forzada y colaboración de agentes, para activar rápidamente todas las funciones avanzadas.","tags":["ultrawork","tareas en segundo plano","colaboración de agentes"],"prerequisite":["start-installation","start-sisyphus-orchestrator"],"order":30},"headers":[],"relativePath":"es/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md","filePath":"es/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"}'),s={name:"es/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"};function n(i,e,l,d,c,u){return t(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="modo-ultrawork-activa-todas-las-funciones" tabindex="-1">Modo Ultrawork: Activa Todas las Funciones <a class="header-anchor" href="#modo-ultrawork-activa-todas-las-funciones" aria-label="Permalink to &quot;Modo Ultrawork: Activa Todas las Funciones&quot;">​</a></h1><h2 id="que-aprenderas" tabindex="-1">Qué Aprenderás <a class="header-anchor" href="#que-aprenderas" aria-label="Permalink to &quot;Qué Aprenderás&quot;">​</a></h2><ul><li>Activa todas las funciones avanzadas de oh-my-opencode con un solo comando</li><li>Haz que múltiples agentes de IA trabajen en paralelo como un equipo real</li><li>Evita configurar manualmente múltiples agentes y tareas en segundo plano</li><li>Comprende la filosofía de diseño y las mejores prácticas del modo Ultrawork</li></ul><h2 id="tus-desafios-actuales" tabindex="-1">Tus Desafíos Actuales <a class="header-anchor" href="#tus-desafios-actuales" aria-label="Permalink to &quot;Tus Desafíos Actuales&quot;">​</a></h2><p>Es posible que hayas encontrado estas situaciones durante el desarrollo:</p><ul><li><strong>Demasiadas funciones, no sabes cómo usarlas</strong>: Tienes 10 agentes especializados, tareas en segundo plano, herramientas LSP, pero no sabes cómo activarlas rápidamente</li><li><strong>Se requiere configuración manual</strong>: Cada tarea compleja requiere especificar manualmente agentes, concurrencia en segundo plano y otras configuraciones</li><li><strong>Colaboración de agentes ineficiente</strong>: Llamando agentes en serie, desperdiciando tiempo y costos</li><li><strong>Tareas atascadas a mitad de camino</strong>: Los agentes no tienen suficiente motivación y restricciones para completar las tareas</li></ul><p>Todo esto está afectando tu capacidad para desatar el verdadero poder de oh-my-opencode.</p><h2 id="concepto-central" tabindex="-1">Concepto Central <a class="header-anchor" href="#concepto-central" aria-label="Permalink to &quot;Concepto Central&quot;">​</a></h2><p><strong>Modo Ultrawork</strong> es el mecanismo de &quot;activar todo con un clic&quot; de oh-my-opencode.</p><div class="info custom-block"><p class="custom-block-title">¿Qué es el Modo Ultrawork?</p><p>El Modo Ultrawork es un modo de trabajo especial activado por una palabra clave. Cuando tu prompt contiene <code>ultrawork</code> o su abreviatura <code>ulw</code>, el sistema activa automáticamente todas las funciones avanzadas: tareas en segundo plano paralelas, exploración profunda, finalización forzada, colaboración multi-agente y más.</p></div><h3 id="filosofia-de-diseno" tabindex="-1">Filosofía de Diseño <a class="header-anchor" href="#filosofia-de-diseno" aria-label="Permalink to &quot;Filosofía de Diseño&quot;">​</a></h3><p>El modo Ultrawork se basa en los siguientes principios centrales (del <a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer">Ultrawork Manifesto</a>):</p><table tabindex="0"><thead><tr><th>Principio</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>La intervención humana es una señal de fallo</strong></td><td>Si necesitas corregir constantemente la salida de la IA, significa que hay un problema con el diseño del sistema</td></tr><tr><td><strong>Código indistinguible</strong></td><td>El código escrito por la IA no debería distinguirse del código escrito por ingenieros senior</td></tr><tr><td><strong>Minimizar la carga cognitiva</strong></td><td>Solo necesitas decir &quot;qué hacer&quot;, los agentes son responsables de &quot;cómo hacerlo&quot;</td></tr><tr><td><strong>Predecible, consistente, delegable</strong></td><td>Los agentes deberían ser tan estables y confiables como un compilador</td></tr></tbody></table><h3 id="mecanismo-de-activacion" tabindex="-1">Mecanismo de Activación <a class="header-anchor" href="#mecanismo-de-activacion" aria-label="Permalink to &quot;Mecanismo de Activación&quot;">​</a></h3><p>Cuando el sistema detecta la palabra clave <code>ultrawork</code> o <code>ulw</code>:</p><ol><li><strong>Establecer modo de máxima precisión</strong>: <code>message.variant = &quot;max&quot;</code></li><li><strong>Mostrar notificación Toast</strong>: &quot;Ultrawork Mode Activated - Maximum precision engaged. All agents at your disposal.&quot;</li><li><strong>Inyectar instrucciones completas</strong>: Inyectar 200+ líneas de instrucciones ULTRAWORK a los agentes, incluyendo: <ul><li>Requerir 100% de certeza antes de comenzar la implementación</li><li>Requerir uso paralelo de tareas en segundo plano</li><li>Forzar el uso del sistema Category + Skills</li><li>Forzar verificación de finalización (flujo de trabajo TDD)</li><li>Prohibir cualquier excusa de &quot;no puedo hacerlo&quot;</li></ul></li></ol><h2 id="sigue-los-pasos" tabindex="-1">Sigue los Pasos <a class="header-anchor" href="#sigue-los-pasos" aria-label="Permalink to &quot;Sigue los Pasos&quot;">​</a></h2><h3 id="paso-1-activar-el-modo-ultrawork" tabindex="-1">Paso 1: Activar el Modo Ultrawork <a class="header-anchor" href="#paso-1-activar-el-modo-ultrawork" aria-label="Permalink to &quot;Paso 1: Activar el Modo Ultrawork&quot;">​</a></h3><p>Ingresa un prompt que contenga la palabra clave <code>ultrawork</code> o <code>ulw</code> en OpenCode:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ultrawork desarrollar una API REST</span></span></code></pre></div><p>O más conciso:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ulw agregar autenticación de usuario</span></span></code></pre></div><p><strong>Deberías ver</strong>:</p><ul><li>Una notificación Toast aparece en la interfaz: &quot;Ultrawork Mode Activated&quot;</li><li>La respuesta del agente comienza con &quot;ULTRAWORK MODE ENABLED!&quot;</li></ul><h3 id="paso-2-observar-cambios-en-el-comportamiento-del-agente" tabindex="-1">Paso 2: Observar Cambios en el Comportamiento del Agente <a class="header-anchor" href="#paso-2-observar-cambios-en-el-comportamiento-del-agente" aria-label="Permalink to &quot;Paso 2: Observar Cambios en el Comportamiento del Agente&quot;">​</a></h3><p>Después de activar el modo Ultrawork, los agentes:</p><ol><li><p><strong>Exploración paralela del código base</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;encontrar patrones de API existentes&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;encontrar infraestructura de pruebas&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;librarian&quot;, prompt=&quot;encontrar mejores prácticas de autenticación&quot;, background=true)</span></span></code></pre></div></li><li><p><strong>Llamar al agente Plan para crear un plan de trabajo</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(subagent_type=&quot;plan&quot;, prompt=&quot;crear plan detallado basado en el contexto recopilado&quot;)</span></span></code></pre></div></li><li><p><strong>Usar Category + Skills para ejecutar tareas</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(category=&quot;visual-engineering&quot;, load_skills=[&quot;frontend-ui-ux&quot;, &quot;playwright&quot;], ...)</span></span></code></pre></div></li></ol><p><strong>Deberías ver</strong>:</p><ul><li>Múltiples tareas en segundo plano ejecutándose simultáneamente</li><li>Agentes llamando activamente a agentes especializados (Oracle, Librarian, Explore)</li><li>Planes de pruebas completos y desglose de trabajo</li><li>Tareas continúan ejecutándose hasta completar al 100%</li></ul><h3 id="paso-3-verificar-finalizacion-de-tareas" tabindex="-1">Paso 3: Verificar Finalización de Tareas <a class="header-anchor" href="#paso-3-verificar-finalizacion-de-tareas" aria-label="Permalink to &quot;Paso 3: Verificar Finalización de Tareas&quot;">​</a></h3><p>Después de que los agentes completen:</p><ol><li><strong>Mostrar evidencia de verificación</strong>: Salida real de ejecución de pruebas, descripciones de verificación manual</li><li><strong>Confirmar que todos los TODO están completos</strong>: No declararán finalización anticipadamente</li><li><strong>Resumir el trabajo realizado</strong>: Listar qué se hizo y por qué</li></ol><p><strong>Deberías ver</strong>:</p><ul><li>Resultados de pruebas claros (no &quot;debería funcionar&quot;)</li><li>Todos los problemas resueltos</li><li>Sin lista de TODO incompleta</li></ul><h2 id="punto-de-control-✅" tabindex="-1">Punto de Control ✅ <a class="header-anchor" href="#punto-de-control-✅" aria-label="Permalink to &quot;Punto de Control ✅&quot;">​</a></h2><p>Después de completar los pasos anteriores, confirma:</p><ul><li>[ ] Ves una notificación Toast después de ingresar <code>ulw</code></li><li>[ ] La respuesta del agente comienza con &quot;ULTRAWORK MODE ENABLED!&quot;</li><li>[ ] Observas tareas en segundo plano paralelas ejecutándose</li><li>[ ] Los agentes usan el sistema Category + Skills</li><li>[ ] Hay evidencia de verificación después de completar la tarea</li></ul><p>Si algún elemento falla, verifica:</p><ul><li>Si la palabra clave está escrita correctamente (<code>ultrawork</code> o <code>ulw</code>)</li><li>Si estás en la sesión principal (las tareas en segundo plano no activarán el modo)</li><li>Si el archivo de configuración tiene habilitadas las funciones relevantes</li></ul><h2 id="cuando-usar-esta-tecnica" tabindex="-1">Cuándo Usar Esta Técnica <a class="header-anchor" href="#cuando-usar-esta-tecnica" aria-label="Permalink to &quot;Cuándo Usar Esta Técnica&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Escenario</th><th>Usar Ultrawork</th><th>Modo Normal</th></tr></thead><tbody><tr><td><strong>Funciones nuevas complejas</strong></td><td>✅ Recomendado (requiere colaboración multi-agente)</td><td>❌ Puede no ser lo suficientemente eficiente</td></tr><tr><td><strong>Correcciones urgentes</strong></td><td>✅ Recomendado (necesita diagnóstico rápido y exploración)</td><td>❌ Puede perder contexto</td></tr><tr><td><strong>Modificaciones simples</strong></td><td>❌ Excesivo (desperdicia recursos)</td><td>✅ Más adecuado</td></tr><tr><td><strong>Validación rápida de ideas</strong></td><td>❌ Excesivo</td><td>✅ Más adecuado</td></tr></tbody></table><p><strong>Regla general</strong>:</p><ul><li>La tarea involucra múltiples módulos o sistemas → Usa <code>ulw</code></li><li>Necesitas investigación profunda del código base → Usa <code>ulw</code></li><li>Necesitas llamar a múltiples agentes especializados → Usa <code>ulw</code></li><li>Cambio pequeño en un solo archivo → No necesitas <code>ulw</code></li></ul><h2 id="errores-comunes" tabindex="-1">Errores Comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores Comunes&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Notas Importantes</p><p><strong>1. No uses <code>ulw</code> en cada prompt</strong></p><p>El modo Ultrawork inyecta una gran cantidad de instrucciones, lo cual es excesivo para tareas simples. Úsalo solo para tareas complejas que realmente requieran colaboración multi-agente, exploración paralela y análisis profundo.</p><p><strong>2. Las tareas en segundo plano no activarán el modo Ultrawork</strong></p><p>El detector de palabras clave omite las sesiones en segundo plano para evitar inyectar incorrectamente el modo en sub-agentes. El modo Ultrawork solo funciona en la sesión principal.</p><p><strong>3. Asegúrate de que la configuración del Provider sea correcta</strong></p><p>El modo Ultrawork depende de múltiples modelos de IA trabajando en paralelo. Si ciertos Providers no están configurados o no están disponibles, los agentes pueden no ser capaces de llamar a agentes especializados.</p></div><h2 id="resumen-de-la-leccion" tabindex="-1">Resumen de la Lección <a class="header-anchor" href="#resumen-de-la-leccion" aria-label="Permalink to &quot;Resumen de la Lección&quot;">​</a></h2><p>El modo Ultrawork logra el objetivo de diseño de &quot;activar todas las funciones con un comando&quot; a través de la activación por palabras clave:</p><ul><li><strong>Fácil de usar</strong>: Solo ingresa <code>ulw</code> para activar</li><li><strong>Colaboración automática</strong>: Los agentes llaman automáticamente a otros agentes y ejecutan tareas en segundo plano en paralelo</li><li><strong>Finalización forzada</strong>: Mecanismo de verificación completo asegura finalización al 100%</li><li><strong>Cero configuración</strong>: No necesitas configurar manualmente prioridades de agentes, límites de concurrencia, etc.</li></ul><p>Recuerda: El modo Ultrawork está diseñado para hacer que los agentes trabajen como un equipo real. Solo necesitas expresar la intención, los agentes son responsables de la ejecución.</p><h2 id="vista-previa-de-la-siguiente-leccion" tabindex="-1">Vista Previa de la Siguiente Lección <a class="header-anchor" href="#vista-previa-de-la-siguiente-leccion" aria-label="Permalink to &quot;Vista Previa de la Siguiente Lección&quot;">​</a></h2><blockquote><p>En la siguiente lección, aprenderemos <strong><a href="./../../platforms/provider-setup/">Configuración de Provider</a></strong>.</p><p>Aprenderás:</p><ul><li>Cómo configurar múltiples Providers como Anthropic, OpenAI, Google</li><li>Cómo la estrategia multi-modelo degrada automáticamente y selecciona modelos óptimos</li><li>Cómo probar conexiones de Provider y uso de cuota</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fuente" tabindex="-1">Apéndice: Referencia de Código Fuente <a class="header-anchor" href="#apendice-referencia-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia de Código Fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir ubicaciones del código fuente</strong></summary><blockquote><p>Última actualización: 2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del Archivo</th><th>Números de Línea</th></tr></thead><tbody><tr><td>Filosofía de diseño Ultrawork</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer"><code>docs/ultrawork-manifesto.md</code></a></td><td>1-198</td></tr><tr><td>Hook detector de palabras clave</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/index.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/index.ts</code></a></td><td>12-100</td></tr><tr><td>Plantilla de instrucciones ULTRAWORK</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/constants.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/constants.ts</code></a></td><td>54-280</td></tr><tr><td>Lógica de detección de palabras clave</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/detector.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/detector.ts</code></a></td><td>26-53</td></tr></tbody></table><p><strong>Constantes clave</strong>:</p><ul><li><code>KEYWORD_DETECTORS</code>: Configuración del detector de palabras clave, incluyendo tres modos: ultrawork, search, analyze</li><li><code>CODE_BLOCK_PATTERN</code>: Patrón regex de bloques de código, usado para filtrar palabras clave en bloques de código</li><li><code>INLINE_CODE_PATTERN</code>: Patrón regex de código en línea, usado para filtrar palabras clave en código en línea</li></ul><p><strong>Funciones clave</strong>:</p><ul><li><code>createKeywordDetectorHook()</code>: Crea Hook detector de palabras clave, escucha evento UserPromptSubmit</li><li><code>detectKeywordsWithType()</code>: Detecta palabras clave en texto y devuelve tipo (ultrawork/search/analyze)</li><li><code>getUltraworkMessage()</code>: Genera instrucciones completas del modo ULTRAWORK (selecciona Planner o modo normal según el tipo de agente)</li><li><code>removeCodeBlocks()</code>: Elimina bloques de código del texto para evitar activar palabras clave en bloques de código</li></ul><p><strong>Reglas de negocio</strong>:</p><table tabindex="0"><thead><tr><th>ID de Regla</th><th>Descripción de la Regla</th><th>Etiqueta</th></tr></thead><tbody><tr><td>BR-4.8.4-1</td><td>Activar modo Ultrawork cuando se detecta &quot;ultrawork&quot; o &quot;ulw&quot;</td><td>[Hecho]</td></tr><tr><td>BR-4.8.4-2</td><td>El modo Ultrawork establece <code>message.variant = &quot;max&quot;</code></td><td>[Hecho]</td></tr><tr><td>BR-4.8.4-3</td><td>El modo Ultrawork muestra notificación Toast: &quot;Ultrawork Mode Activated&quot;</td><td>[Hecho]</td></tr><tr><td>BR-4.8.4-4</td><td>Las sesiones de tareas en segundo plano omiten la detección de palabras clave para evitar inyección de modo</td><td>[Hecho]</td></tr><tr><td>BR-4.8.4-5</td><td>Las sesiones no principales solo permiten la palabra clave ultrawork, bloqueando otras inyecciones de modo</td><td>[Hecho]</td></tr></tbody></table></details>`,54)])])}const g=a(s,[["render",n]]);export{m as __pageData,g as default};
